1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("Quote - base premiums", () => {
6	    it("returns 5G premium for empty items list (processing fee only)", () => {
7	      const result = processScenario({
8	        customer: { yearsWithMHPCO: 0 },
9	        steps: [{ op: "quote" as const, items: [] }],
10	      });
11	      expect(result.results[0]).toEqual({ premium: 5 });
12	    });
13	    it.todo("computes premium for a single sword (100G base + 5G fee = 105G)");
14	    it.todo("computes premium for a single amulet (60G base + 5G fee = 65G)");
15	    it.todo("computes premium for multiple items (sword + amulet = 160G base + 5G fee)");
16	  });
17	
18	  describe("Quote - component premiums", () => {
19	    it.todo("computes premium for 2 runes (50G base + 5G fee)");
20	    it.todo("computes premium for a block of 3 alike components (60G base + 5G fee)");
21	    it.todo("computes premium for 4 runes (100G base, no block + 5G fee)");
22	    it.todo("computes premium for mixed components, no block (2 runes + 1 moonstone = 75G base + 5G fee)");
23	    it.todo("computes premium for two separate blocks (3 runes + 3 moonstones = 120G base + 5G fee)");
24	  });
25	
26	  describe("Quote - item-specific modifiers", () => {
27	    it.todo("adds 50% cursed surcharge to a cursed item's base premium");
28	    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
29	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
30	    it.todo("applies cursed surcharge only to the cursed item in a multi-item policy");
31	  });
32	
33	  describe("Quote - policy-wide modifiers", () => {
34	    it.todo("adds 10% first insurance surcharge (applied to every quote)");
35	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
36	    it.todo("applies 15% follow-up discount on second and subsequent quotes");
37	    it.todo("combines loyalty, first insurance, and follow-up modifiers");
38	  });
39	
40	  describe("Quote - rounding", () => {
41	    it.todo("rounds premium up in MHPCO's favor");
42	  });
43	
44	  describe("Quote - errors", () => {
45	    it.todo("throws error for unknown item type");
46	  });
47	
48	  describe("Claim - basic payout", () => {
49	    it.todo("applies 100G deductible per damaged item");
50	    it.todo("applies deductible to each item independently in multi-item damage");
51	  });
52	
53	  describe("Claim - reimbursement rules", () => {
54	    it.todo("reimburses at 50% for items with enchantment >= 8");
55	    it.todo("fully reimburses damage to dragon-material items");
56	    it.todo("applies 50% rule when item has both enchantment >= 8 and dragon material");
57	    it.todo("fully reimburses dragon-material item with enchantment < 8");
58	  });
59	
60	  describe("Claim - cap", () => {
61	    it.todo("caps total payout at 2x insurance sum");
62	    it.todo("tracks remaining cap across successive claims");
63	  });
64	
65	  describe("Claim - rounding", () => {
66	    it.todo("rounds payout down in MHPCO's favor");
67	  });
68	
69	  describe("Claim - errors", () => {
70	    it.todo("throws error when damage references item not in policy");
71	    it.todo("throws error for negative damage amount");
72	    it.todo("throws error when more damages of a type than items insured");
73	  });
74	
75	  describe("Integration", () => {
76	    it.todo("newcomer with cursed sword: premium 165G");
77	    it.todo("long-standing customer second contract with cursed enchanted sword: premium 160G");
78	  });
79	});
80

